ALTER TYPE "CompanyExpenseType" ADD VALUE IF NOT EXISTS 'MAINTENANCE';
ALTER TYPE "CompanyExpenseType" ADD VALUE IF NOT EXISTS 'AOG_RECOVERY';
ALTER TYPE "CompanyExpenseType" ADD VALUE IF NOT EXISTS 'MAINTENANCE_FERRY_SUPPORT';
CREATE TYPE "AircraftOperationalStatus" AS ENUM ('NORMAL','WATCH','CAUTION','MAINT_REQUIRED','FERRY_ONLY','IN_MAINTENANCE','AOG');
CREATE TYPE "AircraftMaintenanceStatus" AS ENUM ('NONE','REQUIRED','FERRY_TO_BASE','WAITING_MAINTENANCE','IN_PROGRESS','COMPLETED','CANCELLED');
CREATE TYPE "AircraftMaintenanceType" AS ENUM ('LINE_CHECK','SCHEDULED_CHECK','HEAVY_CHECK','AOG_RECOVERY');
ALTER TABLE "CompanyExpense" ALTER COLUMN "pirepId" DROP NOT NULL, ADD COLUMN "maintenanceOrderId" TEXT;
CREATE UNIQUE INDEX "CompanyExpense_maintenanceOrderId_key" ON "CompanyExpense"("maintenanceOrderId");
ALTER TABLE "FlightOffer" ADD COLUMN "offerType" TEXT NOT NULL DEFAULT 'STANDARD';
CREATE TABLE "AircraftConditionSnapshot" ("id" TEXT NOT NULL,"vamsysAircraftId" TEXT NOT NULL,"registration" TEXT,"aircraftType" TEXT,"conditionPercent" DECIMAL(5,2) NOT NULL DEFAULT 100,"operationalStatus" "AircraftOperationalStatus" NOT NULL DEFAULT 'NORMAL',"maintenanceStatus" "AircraftMaintenanceStatus" NOT NULL DEFAULT 'NONE',"maintenanceBaseIcao" TEXT NOT NULL DEFAULT 'LEVC',"cyclesSinceMaintenance" INTEGER NOT NULL DEFAULT 0,"blockMinutesSinceMaintenance" INTEGER NOT NULL DEFAULT 0,"lastWearPirepId" TEXT,"lastVamsysPirepId" TEXT,"lastMaintenanceAt" TIMESTAMP(3),"notes" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "AircraftConditionSnapshot_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "AircraftConditionSnapshot_vamsysAircraftId_key" ON "AircraftConditionSnapshot"("vamsysAircraftId");
CREATE TABLE "AircraftWearEvent" ("id" TEXT NOT NULL,"vamsysAircraftId" TEXT NOT NULL,"localPirepId" TEXT NOT NULL,"vamsysPirepId" TEXT,"previousCondition" DECIMAL(5,2) NOT NULL,"wearPercent" DECIMAL(5,2) NOT NULL,"newCondition" DECIMAL(5,2) NOT NULL,"blockMinutes" INTEGER,"landingRate" INTEGER,"landingG" DECIMAL(4,2),"aircraftType" TEXT,"factors" JSONB NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AircraftWearEvent_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "AircraftWearEvent_localPirepId_key" ON "AircraftWearEvent"("localPirepId"); CREATE INDEX "AircraftWearEvent_vamsysAircraftId_createdAt_idx" ON "AircraftWearEvent"("vamsysAircraftId","createdAt");
CREATE TABLE "AircraftMaintenanceOrder" ("id" TEXT NOT NULL,"vamsysAircraftId" TEXT NOT NULL,"registration" TEXT,"aircraftType" TEXT,"type" "AircraftMaintenanceType" NOT NULL,"status" "AircraftMaintenanceStatus" NOT NULL,"currentCondition" DECIMAL(5,2) NOT NULL,"targetCondition" DECIMAL(5,2) NOT NULL,"estimatedCostCents" INTEGER NOT NULL,"actualCostCents" INTEGER,"maintenanceBaseIcao" TEXT NOT NULL DEFAULT 'LEVC',"currentAirportIcao" TEXT,"ferryOfferId" TEXT,"ferryDispatchId" TEXT,"startedAt" TIMESTAMP(3),"completedAt" TIMESTAMP(3),"notes" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "AircraftMaintenanceOrder_pkey" PRIMARY KEY ("id")); CREATE INDEX "AircraftMaintenanceOrder_vamsysAircraftId_status_idx" ON "AircraftMaintenanceOrder"("vamsysAircraftId","status");
CREATE TABLE "AircraftMaintenanceRule" ("id" TEXT NOT NULL,"aircraftCategory" TEXT NOT NULL,"cycleWearPercent" DECIMAL(5,2) NOT NULL,"hourlyWearPercent" DECIMAL(5,2) NOT NULL,"baseInspectionCostCents" INTEGER NOT NULL,"costPerConditionPointCents" INTEGER NOT NULL,"hangarDailyCostCents" INTEGER NOT NULL,"targetConditionPercent" DECIMAL(5,2) NOT NULL DEFAULT 90,"heavyTargetConditionPercent" DECIMAL(5,2) NOT NULL DEFAULT 95,"mandatoryThresholdPercent" DECIMAL(5,2) NOT NULL DEFAULT 30,"aogThresholdPercent" DECIMAL(5,2) NOT NULL DEFAULT 20,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "AircraftMaintenanceRule_pkey" PRIMARY KEY ("id")); CREATE UNIQUE INDEX "AircraftMaintenanceRule_aircraftCategory_key" ON "AircraftMaintenanceRule"("aircraftCategory");
